css:
h1 { color: #333; font-size: 24px; } .container {
  display: flex;
  flex-wrap: wrap;
}

.column {
  width: 50%;

  box-sizing: border-box;
}

.column img {
  width: 60%;
 float: right;
 height: auto;
}

/* Media query for small screens */
@media (max-width: 600px) {
  .column {
    width: 100%;
  }

  .column:first-child {
    order: 2;
  }

  .column:last-child {
    order: 1;
  }
}
